--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -13533,6 +13533,26 @@ Value *BoUpSLP::gather(ArrayRef<Value *> VL, Value *Root, Type *ScalarTy) {
   };
   auto *VecTy = getWidenedType(ScalarTy, VL.size());
   Value *Vec = PoisonValue::get(VecTy);
+  // If Root is a vector with a different number of elements than VecTy,
+  // we need to adjust it to match VecTy.
+  if (Root && Root->getType() != VecTy) {
+    auto *RootVTy = dyn_cast<VectorType>(Root->getType());
+    if (RootVTy && RootVTy->getElementType() == ScalarTy) {
+      unsigned RootSize = RootVTy->getElementCount().getKnownMinValue();
+      unsigned VecSize = cast<FixedVectorType>(VecTy)->getNumElements();
+      if (RootSize < VecSize) {
+        // Widen Root by shuffling with poison.
+        SmallVector<int> WidenedMask(VecSize, PoisonMaskElem);
+        for (unsigned I = 0; I < RootSize; ++I)
+          WidenedMask[I] = I;
+        Root = Builder.CreateShuffleVector(Root, PoisonValue::get(RootVTy),
+                                           WidenedMask);
+      }
+      // If RootSize > VecSize, we cannot use Root; treat as null.
+    }
+  }
+  if (Root && Root->getType() != VecTy)
+    Root = nullptr;
   SmallVector<int> NonConsts;
   SmallVector<int> Mask(VL.size());
   std::iota(Mask.begin(), Mask.end(), 0);
